mapper.select:
/* selectMcodem */ SELECT COMCDVL, COMCDTX, COMCDKY, COMCDVL, COMCDOR , COMCDSY, COMMEMO, CDCATE1, CDCATE2, CDCATE3 , CDATTR1, CDATTR2, CDATTR3 FROM ${userData.schema}.MCODEM WHERE COUSEYN = 'Y'
AND COMCDSY IN ('Y', 'N')
AND COMCDSY = 'N'
AND COMCDKY = #{params.comcdky}
ORDER BY COMCDKY, COMCDOR ASC

/* selectCode */
SELECT COMCDVL, COMCDTX, COMCDKY, COMCDVL, COMCDOR
	 , COMCDSY, COMMEMO, CDCATE1, CDCATE2, CDCATE3
	 , CDATTR1, CDATTR2, CDATTR3
  FROM ${userData.schema}.MCODEM
 WHERE COUSEYN = 'Y'


         AND COMCDSY IN ('Y', 'N')


	     AND COMCDSY = 'N'



     AND COMCDKY = #{param.comcdky}


     AND COMCDVL = #{param.comcdvl}

mapper.insert:
	/* insertMcodem */
	INSERT INTO ${userData.schema}.MCODEM(
		   COMCDKY, COMCDVL, COMKYTX, COMCDTX, COMCDOR
		 , COMCDSY, COMMEMO, CDCATE1, CDCATE2, CDCATE3
		 , CDATTR1, CDATTR2, CDATTR3, COUSEYN, CREDATE
		 , CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER
  ) VALUES (
  		   UPPER(#{addData.comcdky}), UPPER(#{addData.comcdvl}), #{addData.comkytx}
		 , #{addData.comcdtx}, #{addData.comcdor}, #{addData.comcdsy}
		 , #{addData.commemo}, #{addData.cdcate1}, #{addData.cdcate2}
		 , #{addData.cdcate3}, #{addData.cdattr1}, #{addData.cdattr2}
		 , #{addData.cdattr3}, #{addData.couseyn}
		 , to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
		 , to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
  )

mapper.update:
/* updateMcodem */
UPDATE ${userData.schema}.MCODEM SET
	   COMCDKY = #{updateData.comcdky}
	 , COMCDVL = #{updateData.comcdvl}
	 , COMKYTX = #{updateData.comkytx}
	 , COMCDTX = #{updateData.comcdtx}
	 , COMCDOR = #{updateData.comcdor}
	 , COMCDSY = #{updateData.comcdsy}
	 , COMMEMO = #{updateData.commemo}
	 , CDCATE1 = #{updateData.cdcate1}
	 , CDCATE2 = #{updateData.cdcate2}
	 , CDCATE3 = #{updateData.cdcate3}
	 , CDATTR1 = #{updateData.cdattr1}
	 , CDATTR2 = #{updateData.cdattr2}
	 , CDATTR3 = #{updateData.cdattr3}
	 , COUSEYN = #{updateData.couseyn}
	 , LMODATE = to_char(NOW() ,'YYYYMMDD')
	 , LMOTIME = to_char(NOW() ,'hh24miss')
	 , LMOUSER = #{userData.useract}
	 , UPDTCHK = #{updateData.updtchk} + 1
 WHERE UPDTCHK = #{updateData.updtchk}


		 AND COMCDKY = #{updateData.oldComcdky}


		 AND COMCDKY = #{updateData.comcdky}




		 AND COMCDVL = #{updateData.oldComcdvl}


		 AND COMCDVL = #{updateData.comcdvl}

mapper.select:
/* selectMcodemSelectBox */
SELECT COMCDVL as COMBOVL, COMCDTX as COMBONM
  FROM ${userData.schema}.MCODEM
 WHERE COUSEYN = 'Y'


         AND COMCDSY IN ('Y', 'N')


		 AND COMCDSY = 'N'




     AND COMCDKY = #{params.comcdky}



     AND COMCDKY IN

         #{item}




	 AND COMCDVL = #{params.comcdvl}



	 AND COMCDVL IN

		 #{item}



	 AND CDCATE1 = #{params.cdcate1}


	 AND CDCATE2 = #{params.cdcate2}


	 AND CDCATE3 = #{params.cdcate3}

 GROUP BY COMCDVL, COMCDTX
 ORDER BY COMCDOR ASC

/* selectMrscmaList */ SELECT CONCAT(MR.WAREKEY, MR.DOCCATE, MR.DOCCATE, MR.RSNCODE) AS rowkey , MR.WAREKEY, MR.DOCCATE, MD.DOCCTNM AS DOCCTNM, MR.DOCTYPE , MD.DOCTYNM AS DOCTYNM, MR.RSNCODE, MR.RSNCDNM, MR.RSNCDOD , MR.RSCATE1, MR.RSCATE2, MR.RSCATE3, MR.RSATTR1, MR.RSATTR2 , MR.RSATTR3, MR.RSUSEYN, MR.UPDTCHK , DATE_FORMAT(MR.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(MR.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(MR.CREUSER) AS CREUSER , DATE_FORMAT(MR.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(MR.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(MR.LMOUSER) AS LMOUSER FROM ${userData.schema}.MRSCMA MR INNER JOIN ${userData.schema}.MDOCMA MD ON MR.WAREKEY = MD.WAREKEY AND MR.DOCCATE = MD.DOCCATE AND MR.DOCTYPE = MD.DOCTYPE AND DOUSEYN = 'Y'
AND MR.WAREKEY = #{params.warekey}
AND UPPER(MD.DOCCTNM) LIKE CONCAT('%' , UPPER(#{params.docctnm}) , '%')
AND UPPER(MD.DOCTYNM) LIKE CONCAT('%' , UPPER(#{params.doctynm}) , '%')
AND UPPER(MR.RSNCDNM) LIKE CONCAT('%' , UPPER(#{params.rsncdnm}) , '%')
AND MR.RSUSEYN = #{params.rsuseyn}
ORDER BY MR.DOCCATE, MR.DOCTYPE, MR.RSNCDOD

mapper.insert:
/* insertMrscma */
INSERT INTO ${userData.schema}.MRSCMA(
	WAREKEY, DOCCATE, DOCTYPE, RSNCODE, RSNCDNM
	, RSNCDOD, RSCATE1, RSCATE2, RSCATE3, RSATTR1
	, RSATTR2, RSATTR3, RSUSEYN, CREDATE, CRETIME
	, CREUSER, LMODATE, LMOTIME, LMOUSER
)VALUES(
	#{addData.warekey}, #{addData.doccate}, #{addData.doctype}
	, #{addData.rsncode}, #{addData.rsncdnm}, #{addData.rsncdod}
	, #{addData.rscate1}, #{addData.rscate2}, #{addData.rscate3}
	, #{addData.rsattr1}, #{addData.rsattr2}, #{addData.rsattr3}, #{addData.rsuseyn}
	, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
	, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
)

mapper.update:
/* updateMrscma */
UPDATE ${userData.schema}.MRSCMA SET
	DOCCATE = #{updateData.doccate}
	, DOCTYPE = #{updateData.doctype}
	, RSNCODE = #{updateData.rsncode}
	, RSNCDNM = #{updateData.rsncdnm}
	, RSNCDOD = #{updateData.rsncdod}
	, RSCATE1 = #{updateData.rscate1}
	, RSCATE2 = #{updateData.rscate2}
	, RSCATE3 = #{updateData.rscate3}
	, RSATTR1 = #{updateData.rsattr1}
	, RSATTR2 = #{updateData.rsattr2}
	, RSATTR3 = #{updateData.rsattr3}
	, RSUSEYN = #{updateData.rsuseyn}
	, LMODATE = to_char(NOW() ,'YYYYMMDD')
	, LMOTIME = to_char(NOW() ,'hh24miss')
	, LMOUSER = #{userData.useract}
	, UPDTCHK = #{updateData.updtchk} + 1
WHERE UPDTCHK = #{updateData.updtchk}


		AND WAREKEY = #{updateData.oldWarekey}


		AND WAREKEY = #{updateData.warekey}




		AND DOCCATE = #{updateData.oldDoccate}


		AND DOCCATE = #{updateData.doccate}




		AND DOCTYPE = #{updateData.oldDoctype}


		AND DOCTYPE = #{updateData.doctype}




		AND RSNCODE = #{updateData.oldRsncode}


		AND RSNCODE = #{updateData.rsncode}

mapper.select:
/* selectMrscmaSelectBox */
SELECT RSNCODE AS COMBOVL, RSNCDNM AS COMBONM, RSCATE1
  FROM ${userData.schema}.MRSCMA
 WHERE RSUSEYN = 'Y'

 	 and WAREKEY = #{params.warekey}


 	 and DOCCATE = #{params.doccate}


 	 and DOCTYPE = #{params.doctype}

/* selectMrscmaRelationList */
SELECT MRS.WAREKEY, MRS.DOCCATE, MRS.DOCTYPE
	 , MRS.RSNCODE, MRS.RSNCDNM, MRS.RSCATE1
  FROM ${userData.schema}.MRSCMA MRS
 INNER JOIN ${userData.schema}.MDOCMA MDO
 		 ON (MDO.WAREKEY = MRS.WAREKEY AND MDO.DOCCATE = MRS.DOCCATE AND MDO.DOCTYPE = MRS.DOCTYPE)


         MRS.WAREKEY = #{param.warekey}


	 MRS.RSUSEYN = #{param.rsuseyn}


 ORDER BY MRS.RSNCDOD
